mapper.update:
UPDATE residence_history
SET move_out_date = #{moveOutDate}, move_out_reason = #{moveOutReason}, updated_at = #{updatedAt}
WHERE residence_history_id = #{residenceHistoryId} AND deleted_at IS NULL

mapper.select:
SELECT rh.residence_history_id, rh.employee_id, e.name AS employee_name, rh.dormitory_id, d.name AS dormitory_name, rh.room_id, r.room_name, rh.move_in_date, rh.move_out_date, rh.move_out_reason, rh.usage_type_code, ut.name AS usage_type_name FROM residence_history rh JOIN employee e ON e.employee_id = rh.employee_id AND e.deleted_at IS NULL JOIN dormitory d ON d.dormitory_id = rh.dormitory_id AND d.deleted_at IS NULL JOIN room r ON r.room_id = rh.room_id AND r.deleted_at IS NULL LEFT JOIN usage_type ut ON ut.code = rh.usage_type_code AND ut.deleted_at IS NULL WHERE rh.deleted_at IS NULL
AND e.name ILIKE CONCAT('%', #{name}, '%')
AND rh.employee_id ILIKE CONCAT('%', #{employeeId}, '%')
AND d.name ILIKE CONCAT('%', #{dormitoryName}, '%')
AND rh.move_in_date >= #{moveInDateFrom}
AND rh.move_in_date <= #{moveInDateTo}
ORDER BY rh.move_in_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1) FROM residence_history rh JOIN employee e ON e.employee_id = rh.employee_id AND e.deleted_at IS NULL JOIN dormitory d ON d.dormitory_id = rh.dormitory_id AND d.deleted_at IS NULL WHERE rh.deleted_at IS NULL
AND e.name ILIKE CONCAT('%', #{name}, '%')
AND rh.employee_id ILIKE CONCAT('%', #{employeeId}, '%')
AND d.name ILIKE CONCAT('%', #{dormitoryName}, '%')
AND rh.move_in_date >= #{moveInDateFrom}
AND rh.move_in_date <= #{moveInDateTo}

SELECT residence_history_id, employee_id, dormitory_id, room_id, move_in_date, move_out_date, move_out_reason, usage_type_code, created_at, updated_at, deleted_at FROM residence_history WHERE room_id = #{roomId} AND deleted_at IS NULL AND daterange(move_in_date, COALESCE(move_out_date, 'infinity'::date), '[]') && daterange(#{moveInDate}, COALESCE(#{moveOutDate}, 'infinity'::date), '[]')
AND residence_history_id <> #{excludeId}
ORDER BY move_in_date, residence_history_id

SELECT COUNT(1)
FROM employee_first_dorm_use f
WHERE EXTRACT(YEAR FROM AGE(CURRENT_DATE, f.first_use_date)) >= #{thresholdYears}

SELECT residence_history_id, employee_id, dormitory_id, room_id, move_in_date, move_out_date,
       move_out_reason, usage_type_code, created_at, updated_at, deleted_at
FROM residence_history
WHERE dormitory_id = #{dormitoryId}
  AND employee_id = #{employeeId}
  AND deleted_at IS NULL
  AND move_in_date <= #{asOfDate}
  AND (move_out_date IS NULL OR move_out_date >= #{asOfDate})
ORDER BY move_in_date DESC, residence_history_id DESC
LIMIT 1

SELECT rh.residence_history_id, rh.employee_id, e.name AS employee_name, rh.dormitory_id, d.name AS dormitory_name, d.region, rh.room_id, r.room_name, r.area_sqm, r.room_type, rh.move_in_date, rh.move_out_date, rh.usage_type_code, ut.name AS usage_type_name FROM residence_history rh JOIN employee e ON e.employee_id = rh.employee_id AND e.deleted_at IS NULL JOIN dormitory d ON d.dormitory_id = rh.dormitory_id AND d.deleted_at IS NULL JOIN room r ON r.room_id = rh.room_id AND r.deleted_at IS NULL LEFT JOIN usage_type ut ON ut.code = rh.usage_type_code AND ut.deleted_at IS NULL WHERE rh.deleted_at IS NULL AND rh.move_in_date <= #{monthEnd} AND (rh.move_out_date IS NULL OR rh.move_out_date >= #{monthStart})
AND rh.employee_id = #{employeeId}
AND rh.dormitory_id = #{dormitoryId}
AND rh.room_id = #{roomId}
ORDER BY e.name, d.name, r.room_name, rh.move_in_date
